const toneByStatus = {
  ACTIVE: 'success',
  BLOCKED: 'danger',
  PENDING: 'warning',
  PENDING_VERIFICATION: 'warning',
  REVIEWED: 'secondary',
  PASS: 'success',
  FAIL: 'danger',
  DISABLED: 'secondary',
};

const labelByStatus = {
  ACTIVE: 'Active',
  BLOCKED: 'Blocked',
  PENDING: 'Pending',
  PENDING_VERIFICATION: 'Pending verification',
  REVIEWED: 'Reviewed',
  PASS: 'Pass',
  FAIL: 'Fail',
  DISABLED: 'Disabled',
};

export default function StatusBadge({ status }) {
  const normalized = String(status || 'UNKNOWN').toUpperCase();
  const tone = toneByStatus[normalized] || 'secondary';
  const label = labelByStatus[normalized] || normalized;

  return <span className={`badge text-bg-${tone}`}>{label}</span>;
}
